// ===== items art (consumables) =====================================
// Shared local shape helpers (no import/export). Drawn with documented
// Painter primitives + sym only. Each defineIcon already adds panel + outline.

// Tall vertical glass-shine streak down a bulb at column `x`, rows [y0,y1].
function _glassShine(p, x, y0, y1) {
  for (let y = y0; y <= y1; y++) {
    p.px(x, y, withAlpha(P.white, y === y0 ? 0.85 : 0.4));
  }
  p.px(x + 1, y0 + 1, withAlpha(P.white, 0.25));
}

// A glass flask/potion filled with `liquid`. tall=true draws a rounder bulb.
// Now with a glowing liquid core, a bright surface meniscus, a vertical glass
// streak and a tiny kira glint — reads like backlit potion glass.
function _flask(p, liquid, tall) {
  const dl = darken(liquid, 0.34), ll = lighten(liquid, 0.42), gl = lighten(liquid, 0.7);
  const cy = tall ? 10 : 9, ry = tall ? 5 : 4;
  // inner luminescence behind the glass
  p.glow(8, cy, ry + 1, liquid, 0.4, 4);
  // cork + neck (wood with a bone cap glint and a steel collar)
  p.rect(6, 2, 4, 2, P.woodL);
  p.rect(6, 2, 4, 1, P.bone);
  p.px(6, 2, lighten(P.bone, 0.25));
  p.rect(6, 4, 4, 1, P.gray4);
  p.rect(7, 4, 2, 2, P.gray3);
  p.px(7, 4, P.steelL);
  // bulb glass shell + liquid body
  p.ellipse(8, cy, 4, ry, dl);
  p.ellipse(8, cy, 3, ry - 1, liquid);
  p.ellipse(8, cy + 0.6, 2.2, ry - 1.6, ll);   // lit core, biased up-left of fill
  p.ellipse(7.2, cy - 0.4, 1.1, ry - 2.4, gl);
  // bright liquid surface meniscus
  p.ellipse(8, cy - ry + 1, 2.4, 1, ll);
  p.hline(6.5, 9.5, cy - ry + 1, gl);
  // glass shine streak + specular dots + sealed-glass dark edge
  _glassShine(p, 6, cy - ry + 1, cy + ry - 2);
  p.px(5, cy, P.white);
  p.px(10, cy + 1, dl);
  p.px(11, cy + 1, withAlpha(P.ink, 0.5));
  p.sparkle(6, cy - ry + 1, P.glint, 1);
}

// A heraldic shield shape filled with metal `c`, with an emblem hook.
// Beveled rim light, darker lower half and a clean specular edge for read.
function _shield(p, c) {
  const dc = darken(c, 0.26), lc = lighten(c, 0.32), hc = lighten(c, 0.55);
  for (let y = 3; y <= 13; y++) {
    const t = (y - 3) / 10;
    let w = 4.4 * (1 - t * 0.5);
    if (y > 10) w *= (14 - y) / 3.5;     // taper to a point at the bottom
    p.hline(8 - w, 7 + w, y, t < 0.45 ? mix(c, lc, 0.3 - t) : mix(c, dc, t));
  }
  p.hline(5, 10, 3, lc);                 // top rim light
  p.px(5, 3, hc); p.px(6, 3, hc);
  p.vline(4, 9, 8, lc);                  // left bevel
  p.vline(4, 7, 9, hc);                  // bright left edge glint
  p.hline(5, 9, 12, dc);                 // shaded lower band
}

// A small crystal shard cluster (for shard-themed icons).
// Faceted with an inner glow, a bright facet and a glint at the tip.
function _crystal(p, c) {
  const dc = darken(c, 0.3), lc = lighten(c, 0.38), gl = lighten(c, 0.62);
  p.glow(8, 8.5, 3, c, 0.35, 3);
  p.ellipse(8, 9, 2.4, 4.4, dc);
  p.ellipse(8, 9, 1.5, 3.4, c);
  p.vline(6, 12, 7, lc);                 // lit left facet
  p.vline(5, 12, 8, lc);
  p.vline(5, 9, 9, gl);
  p.px(9, 7, dc);                        // shaded right facet
  p.px(8, 5, P.white);
  p.sparkle(8, 5, P.glint, 1);
}

